SELECT regulation_type, COUNT(*) AS regulation_count
FROM gene_regulations
GROUP BY regulation_type;

SELECT AVG(overlap_value) AS average_overlap, COUNT(*) AS record_count
FROM gene_overlaps
WHERE overlap_type = 'co-regulation';

SELECT COUNT(*) AS inhibition_count
FROM gene_regulations
WHERE regulation_type = 'inhibition';

SELECT regulation_type
FROM tissue_regulations
WHERE tissue_id = 0 AND regulation_type = 'inhibition';

SELECT pathway_name, pathway_description
FROM signaling_pathways
ORDER BY pathway_name ASC;

SELECT gene_id1, gene_id2, SUM(overlap_value) AS total_overlap
FROM gene_overlaps
GROUP BY gene_id1, gene_id2;

SELECT overlap_id, overlap_type
FROM gene_overlaps
WHERE overlap_value > 10;

SELECT interaction_type
FROM pathway_interactions
WHERE pathway_id1 = 1 AND pathway_id2 = 0;
